import{_ as i,o,c as t,ai as a,b1 as n}from"./chunks/framework.Di2lRXru.js";const f=JSON.parse('{"title":"Information","description":"","frontmatter":{},"headers":[],"relativePath":"homebrew/ldn_mitm.md","filePath":"homebrew/ldn_mitm.md"}'),l={name:"homebrew/ldn_mitm.md"};function r(s,e,c,d,m,h){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="information" tabindex="-1">Information <a class="header-anchor" href="#information" aria-label="Permalink to “Information”">​</a></h1><p>ldn_mitm is a <a href="./index#terminologies">sysmodule</a> that allows you to route the local wireless ad-hoc network traffic of the Switch via the network your Switch is connected to, essentially allowing &quot;LAN&quot; functionality between consoles and emulators using ldn_mitm. More information can be found on the <a href="https://github.com/spacemeowx2/ldn_mitm" target="_blank" rel="noreferrer">ldn_mitm GitHub</a> repository.</p><details class="details custom-block"><summary>Common use cases for ldn_mitm</summary><ul><li>It can be used in combination with <a href="http://lan-play.com/install-switch" target="_blank" rel="noreferrer">lan-play</a></li><li>It can be used in combination with <a href="https://www.teamxlink.co.uk/wiki/Nintendo_Switch_XLink_Kai_Setup" target="_blank" rel="noreferrer">XLink Kai</a></li><li>It can be used in combination with real Switch consoles and emulators</li></ul></details><h2 id="section-i-requirements" tabindex="-1">Section I - Requirements <a class="header-anchor" href="#section-i-requirements" aria-label="Permalink to “Section I - Requirements”">​</a></h2><ul><li>An archive manager like <a href="https://www.7-zip.org/" target="_blank" rel="noreferrer">7-Zip</a></li><li>The latest release of <a href="https://github.com/DefenderOfHyrule/ldn_mitm/releases" target="_blank" rel="noreferrer">ldn_mitm</a> (the <code>ldn_mitm.zip</code> file)</li></ul><h2 id="section-ii-installation" tabindex="-1">Section II - Installation <a class="header-anchor" href="#section-ii-installation" aria-label="Permalink to “Section II - Installation”">​</a></h2><ol><li>Boot into hekate and go to <code>Tools</code> &gt; <code>USB Tools</code> &gt; <code>SD Card</code>, then plug your Switch into your PC via USB.</li><li>Your microSD card should now be accessible on your PC, open it.</li><li>Extract the <code>.zip</code> file to a location on your computer. <ul><li>If your archive manager allows for it, you can also simply open the <code>.zip</code> file directly.</li></ul></li><li>Copy the <em>contents</em> of the (extracted) <code>.zip</code> file to the root of your microSD card. <ul><li><strong>Optional:</strong> You can verify if you&#39;ve installed ldn_mitm correctly, you should have a folder called <code>4200000000000010</code> (ldn_mitm) in <code>sd:/atmosphere/contents</code> and the <code>ldnmitm_config.nro</code> file in <code>sd:/switch/ldnmitm_config</code>.</li></ul></li><li>Boot into CFW.</li></ol><h2 id="section-iii-usage" tabindex="-1">Section III - Usage <a class="header-anchor" href="#section-iii-usage" aria-label="Permalink to “Section III - Usage”">​</a></h2><p>You can enable/disable ldn_mitm by opening the Homebrew menu, opening ldn_mitm&#39;s config app and pressing <code>Y</code> to toggle ldn_mitm.</p><p><img src="'+n+'" alt="ldn_mitm"></p><h2 id="section-iv-troubleshooting" tabindex="-1">Section IV - Troubleshooting <a class="header-anchor" href="#section-iv-troubleshooting" aria-label="Permalink to “Section IV - Troubleshooting”">​</a></h2><h3 id="my-switch-crashes-on-boot-after-i-installed-ldn-mitm" tabindex="-1">My Switch crashes on boot after I installed ldn_mitm! <a class="header-anchor" href="#my-switch-crashes-on-boot-after-i-installed-ldn-mitm" aria-label="Permalink to “My Switch crashes on boot after I installed ldn_mitm!”">​</a></h3><p><strong>Cause:</strong> If your Switch crashes with Error <code>std::abort (0xFFE)</code> and Title ID <code>4200000000000010</code>, you&#39;re using a version of ldn_mitm that&#39;s incompatible with your Atmosphère version. The expected Atmosphère version is mentioned on each release page of an ldn_mitm release.</p><h3 id="ldn-mitm-isn-t-working" tabindex="-1">ldn_mitm isn&#39;t working! <a class="header-anchor" href="#ldn-mitm-isn-t-working" aria-label="Permalink to “ldn_mitm isn&#39;t working!”">​</a></h3><p>Assuming you&#39;ve followed the installation instructions successfully, this is probably due to the archive bit being set on one or more folders/files on your microSD card. This is usually the result of copying files to a microSD card via a Mac. If you are experiencing this issue, try running the archive bit fixer utility via hekate for all files.</p><p>This can be done by booting into hekate and going to <code>Tools</code> &gt; <code>Arch bit • RCM Touch • Pkg1/2</code> &gt; <code>Fix Archive Bit</code>.</p>',16)])])}const p=i(l,[["render",r]]);export{f as __pageData,p as default};
